					<Resizable.Pane defaultSize={40} minSize={15} maxSize={65}>
						<TerminalPanel bind:this={terminalRef} />
					</Resizable.Pane>
				{/if}
			</Resizable.PaneGroup>
		</Resizable.Pane>
	</Resizable.PaneGroup>

	<StatusBar />
</div>
