	type Message = { id: string; role: 'user' | 'assistant'; content: string };

	class Chat {
		messages = $state<Message[]>([]);
		status = $state<MessageStatus>('ready');

		constructor({ messages }: { messages: Message[]; transport?: unknown }) {
